import{_ as i,C as s,o,c as l,a2 as e,E as n,w as p,a as h}from"./chunks/framework.BRk9mohw.js";const b=JSON.parse('{"title":"OAuth","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/oauth.md","filePath":"concepts/oauth.md"}'),d={name:"concepts/oauth.md"};function r(c,a,u,k,g,C){const t=s("Warning");return o(),l("div",null,[a[1]||(a[1]=e('<h1 id="oauth" tabindex="-1">OAuth <a class="header-anchor" href="#oauth" aria-label="Permalink to &quot;OAuth&quot;">​</a></h1><h1 id="oauth-1" tabindex="-1">OAuth <a class="header-anchor" href="#oauth-1" aria-label="Permalink to &quot;OAuth&quot;">​</a></h1><p>OpenClaw 通过 OAuth 支持提供商的&quot;订阅认证&quot;（特别是 <strong>OpenAI Codex (ChatGPT OAuth)</strong>。对于 Anthropic 订阅，请使用 <strong>setup-token</strong> 流程。Anthropic 订阅在 Claude Code 之外的 Usage 在过去对一些用户有限制，所以将其视为用户选择的风险，并自行验证当前的 Anthropic 策略。OpenAI Codex OAuth 明确支持在 OpenClaw 等外部工具中使用。本页解释：</p><p>对于生产环境中的 Anthropic，API 密钥认证是比订阅 setup-token 认证更安全的推荐路径。</p><ul><li>OAuth <strong>令牌交换</strong>的工作原理（PKCE）</li><li>令牌<strong>存储</strong>的位置（以及为什么）</li><li>如何处理<strong>多个账户</strong>（配置文件 + 每会话覆盖）</li></ul><p>OpenClaw 还支持<strong>提供商插件</strong>，它们自带 OAuth 或 API 密钥流程。通过以下方式运行它们：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="令牌接收器-为什么存在" tabindex="-1">令牌接收器（为什么存在） <a class="header-anchor" href="#令牌接收器-为什么存在" aria-label="Permalink to &quot;令牌接收器（为什么存在）&quot;">​</a></h2><p>OAuth 提供商在登录/刷新流程中通常会生成<strong>新的刷新令牌</strong>。某些提供商（或 OAuth 客户端）可以在为同一用户/应用发布新令牌时使旧的刷新令牌失效。</p><p>实际症状：</p><ul><li>通过 OpenClaw 和 Claude Code / Codex CLI 登录 → 之后随机&quot;注销&quot;其中一个</li></ul><p>为减少这种情况，OpenClaw 将 <code>auth-profiles.json</code> 视为<strong>令牌接收器</strong>：</p><ul><li>运行时从<strong>一个地方</strong>读取凭据</li><li>我们可以保留多个配置文件并确定性路由</li></ul><h2 id="存储-令牌存储的位置" tabindex="-1">存储（令牌存储的位置） <a class="header-anchor" href="#存储-令牌存储的位置" aria-label="Permalink to &quot;存储（令牌存储的位置）&quot;">​</a></h2><p>机密按代理存储：</p><ul><li>认证配置文件（OAuth + API 密钥 + 可选的值级引用）：<code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li>旧版兼容文件：<code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth.json</code>（静态 <code>api_key</code> 条目在发现时被清理）</li></ul><p>旧版仅导入文件（仍支持，但不是主要存储）：</p><ul><li><code>~/.openclaw/credentials/oauth.json</code>（首次使用时导入到 <code>auth-profiles.json</code>）</li></ul><p>以上都尊重 <code>$OPENCLAW_STATE_DIR</code>（状态目录覆盖）。完整参考：<a href="/gateway/configuration.html#auth-storage-oauth--api-keys">/网关配置</a></p><p>关于静态机密引用和运行时快照激活行为，请参见<a href="/gateway/secrets.html">机密管理</a>。</p><h2 id="anthropic-setup-token-订阅认证" tabindex="-1">Anthropic setup-token（订阅认证） <a class="header-anchor" href="#anthropic-setup-token-订阅认证" aria-label="Permalink to &quot;Anthropic setup-token（订阅认证）&quot;">​</a></h2>',21)),n(t,null,{default:p(()=>[...a[0]||(a[0]=[h(" Anthropic setup-token 支持是技术兼容性，不是策略保证。 Anthropic 过去曾阻止 Claude Code 之外的某些订阅使用。 决定是否使用订阅认证，并自行验证 Anthropic 的当前条款。 ",-1)])]),_:1}),a[2]||(a[2]=e(`<p>在任何机器上运行 <code>claude setup-token</code>，然后粘贴到 OpenClaw：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre></div><p>如果在其他地方生成了令牌，请手动粘贴：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> paste-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic</span></span></code></pre></div><p>验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><h2 id="oauth-交换-登录如何工作" tabindex="-1">OAuth 交换（登录如何工作） <a class="header-anchor" href="#oauth-交换-登录如何工作" aria-label="Permalink to &quot;OAuth 交换（登录如何工作）&quot;">​</a></h2><p>OpenClaw 的交互式登录流程在 <code>@mariozechner/pi-ai</code> 中实现，并接入向导/命令。</p><h3 id="anthropic-setup-token" tabindex="-1">Anthropic setup-token <a class="header-anchor" href="#anthropic-setup-token" aria-label="Permalink to &quot;Anthropic setup-token&quot;">​</a></h3><p>流程：</p><ol><li>运行 <code>claude setup-token</code></li><li>将令牌粘贴到 OpenClaw</li><li>存储为令牌认证配置文件（无刷新）</li></ol><p>向导路径是 <code>openclaw onboard</code> → 认证选择 <code>setup-token</code>（Anthropic）。</p><h3 id="openai-codex-chatgpt-oauth" tabindex="-1">OpenAI Codex (ChatGPT OAuth) <a class="header-anchor" href="#openai-codex-chatgpt-oauth" aria-label="Permalink to &quot;OpenAI Codex (ChatGPT OAuth)&quot;">​</a></h3><p>OpenAI Codex OAuth 明确支持在 Codex CLI 之外使用，包括 OpenClaw 工作流。</p><p>流程（PKCE）：</p><ol><li>生成 PKCE 验证器/挑战器 + 随机 <code>state</code></li><li>打开 <code>https://auth.openai.com/oauth/authorize?...</code></li><li>尝试在 <code>http://127.0.0.1:1455/auth/callback</code> 捕获回调</li><li>如果回调无法绑定（或您是远程/无头） → 粘贴重定向 URL/代码</li><li>在 <code>https://auth.openai.com/oauth/token</code> 交换</li><li>从访问令牌提取 <code>accountId</code> 并存储 <code>{ access, refresh, expires, accountId }</code></li></ol><p>向导路径是 <code>openclaw onboard</code> → 认证选择 <code>openai-codex</code>。</p><h2 id="刷新-过期" tabindex="-1">刷新 + 过期 <a class="header-anchor" href="#刷新-过期" aria-label="Permalink to &quot;刷新 + 过期&quot;">​</a></h2><p>配置文件存储 <code>expires</code> 时间戳。</p><p>在运行时：</p><ul><li>如果 <code>expires</code> 在未来 → 使用存储的访问令牌</li><li>如果已过期 → 刷新（在文件锁下）并覆盖存储的凭据</li></ul><p>刷新是自动的；您通常不需要手动管理令牌。</p><h2 id="多个账户-配置文件-路由" tabindex="-1">多个账户（配置文件）+ 路由 <a class="header-anchor" href="#多个账户-配置文件-路由" aria-label="Permalink to &quot;多个账户（配置文件）+ 路由&quot;">​</a></h2><p>两种模式：</p><h3 id="_1-首选-分离代理" tabindex="-1">1）首选：分离代理 <a class="header-anchor" href="#_1-首选-分离代理" aria-label="Permalink to &quot;1）首选：分离代理&quot;">​</a></h3><p>如果希望&quot;个人&quot;和&quot;工作&quot;永不交互 → 使用隔离代理（独立会话 + 凭据 + 工作空间）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span></span></code></pre></div><p>然后为每个代理配置认证（使用向导）并将聊天路由到正确的代理。</p><h3 id="_2-高级-一个代理中的多个配置文件" tabindex="-1">2）高级：一个代理中的多个配置文件 <a class="header-anchor" href="#_2-高级-一个代理中的多个配置文件" aria-label="Permalink to &quot;2）高级：一个代理中的多个配置文件&quot;">​</a></h3><p><code>auth-profiles.json</code> 支持同一提供商的多个配置文件 ID。</p><p>选择使用哪个配置文件：</p><ul><li>通过配置顺序全局（<code>auth.order</code>）</li><li>通过 <code>/model ...@&lt;profileId&gt;</code> 每会话</li></ul><p>示例（会话覆盖）：</p><ul><li><code>/model Opus@anthropic:work</code></li></ul><p>如何查看存在哪些配置文件 ID：</p><ul><li><code>openclaw channels list --json</code>（显示 <code>auth[]</code>）</li></ul><p>相关文档：</p><ul><li>[/concepts/model-failover]（轮换 + 冷却规则）</li><li>[/tools/slash-commands]（命令表面）</li></ul>`,38))])}const A=i(d,[["render",r]]);export{b as __pageData,A as default};
